package scalascript.frontend.custom

import scala.annotation.nowarn
import scalascript.frontend.*

/** Walks a `View` tree at emit time and produces JS source that
 *  builds the corresponding DOM via imperative
 *  `document.createElement` / `setAttribute` / `appendChild` calls.
 *
 *  Static-subset only — see `CustomFrameworkBackend` for the
 *  documented A2 limitations (signals snapshot, events skipped,
 *  effects skipped).
 *
 *  Output shape (single ES module, no runtime deps):
 *  {{{
 *  // generated by ScalaScript v1.18 — frontend-custom Phase A2
 *  function mount(root) {
 *    const n0 = document.createElement('div');
 *    n0.setAttribute('class', 'hello');
 *    const n1 = document.createTextNode('Hello, world!');
 *    n0.appendChild(n1);
 *    root.appendChild(n0);
 *  }
 *  mount(document.getElementById('app'));
 *  }}}
 *  Variable names use a fresh counter (`n0`, `n1`, …) so the output
 *  is deterministic and diff-friendly. */
private[custom] object StaticJsEmitter:

  def emit(root: View[?], allComponents: List[ComponentDef]): String =
    val _ = allComponents  // reserved for the codegen-lowering pass when name-based ComponentInstance refs land
    val ctx = new Ctx
    val rootVar = ctx.compile(root)
    val sb = new StringBuilder
    sb ++= "// Generated by ScalaScript v1.18 — frontend-custom Phase A2 / A2b / A2c / A2e / A6.\n"
    sb ++= "// Static + reactive (SignalText / ForSignal) + events (Set/Increment/Toggle/Push/Clear) + refs/portals.\n"

    // A2b — emit reactive signal cells + setSignal helper if any
    // SignalText was visited.  Done once per signal name; later
    // sets call __setSignal which fans out to all subscribers.
    if ctx.reactiveSignals.nonEmpty then
      sb ++= "const __ssc_signals = Object.create(null);\n"
      ctx.reactiveSignals.toSeq.sortBy(_._1).foreach { case (name, initial) =>
        sb ++= s"__ssc_signals[${jsString(name)}] = { value: ${initial}, subs: new Set() };\n"
      }
      sb ++= "function __setSignal(name, value) {\n"
      sb ++= "  const cell = __ssc_signals[name];\n"
      sb ++= "  if (!cell) throw new Error('unknown signal: ' + name);\n"
      sb ++= "  cell.value = value;\n"
      sb ++= "  cell.subs.forEach(fn => fn(value));\n"
      sb ++= "}\n"
      // Expose on window for browser-side tests + manual driving.
      sb ++= "if (typeof window !== 'undefined') window.__setSignal = __setSignal;\n"

    // A2e — emit reactive list cells + setSignalList helper if any
    // ForSignal was visited.  Same shape as the scalar signal table
    // but the value is a Seq and subscribers are notified with the
    // whole list.
    if ctx.reactiveLists.nonEmpty then
      sb ++= "const __ssc_lists = Object.create(null);\n"
      ctx.reactiveLists.toSeq.sortBy(_._1).foreach { case (name, initial) =>
        sb ++= s"__ssc_lists[${jsString(name)}] = { value: ${initial}, subs: new Set() };\n"
      }
      sb ++= "function __setSignalList(name, value) {\n"
      sb ++= "  const cell = __ssc_lists[name];\n"
      sb ++= "  if (!cell) throw new Error('unknown list signal: ' + name);\n"
      sb ++= "  cell.value = value;\n"
      sb ++= "  cell.subs.forEach(fn => fn(value));\n"
      sb ++= "}\n"
      sb ++= "if (typeof window !== 'undefined') window.__setSignalList = __setSignalList;\n"

    // A6 — hoist DOM-ref declarations to module scope so user JS can
    // read them after mount.  `let` (not `const`) because the variable
    // is assigned later, when the matching element is created in the
    // mount() body.  Also expose on window for browser-side imperative
    // access from outside the module.
    if ctx.domRefs.nonEmpty then
      ctx.domRefs.toSeq.sorted.foreach { name =>
        sb ++= s"let $name = null;\n"
      }
      sb ++= "if (typeof window !== 'undefined') {\n"
      ctx.domRefs.toSeq.sorted.foreach { name =>
        sb ++= s"  Object.defineProperty(window, ${jsString(name)}, { get: () => $name, configurable: true });\n"
      }
      sb ++= "}\n"

    sb ++= "function mount(root) {\n"
    ctx.statements.foreach { stmt =>
      sb ++= "  "
      sb ++= stmt
      sb ++= "\n"
    }
    if rootVar != null then
      sb ++= s"  root.appendChild($rootVar);\n"
    sb ++= "}\n"
    sb ++= "mount(document.getElementById('app'));\n"
    sb.toString

  /** Per-emit state: a fresh-variable counter and the accumulating
   *  list of JS statements.  `reactiveSignals` collects every
   *  `ReactiveSignal` referenced by a `SignalText` (or future
   *  reactive View variant) so we can emit one cell per name at
   *  the top of the bundle. */
  private final class Ctx:
    private var counter: Int = 0
    private val _outerStatements: scala.collection.mutable.ArrayBuffer[String] =
      scala.collection.mutable.ArrayBuffer.empty
    val reactiveSignals: scala.collection.mutable.LinkedHashMap[String, String] =
      scala.collection.mutable.LinkedHashMap.empty
    // A2e — list signals indexed the same way; value is the JS array literal.
    val reactiveLists: scala.collection.mutable.LinkedHashMap[String, String] =
      scala.collection.mutable.LinkedHashMap.empty
    // A6 — DOM ref names referenced anywhere in the View tree.  Each
    // gets a `let <name> = null;` declaration at module scope so user
    // JS can read it after mount.  LinkedHashSet preserves first-seen
    // order for deterministic output.
    val domRefs: scala.collection.mutable.LinkedHashSet[String] =
      scala.collection.mutable.LinkedHashSet.empty

    // A2e.2 — while emitting an `itemTemplate`, statements go into a
    // separate buffer so we can wrap them in `function __render_item_x(__item, __idx)`.
    // `inItemTemplate` lets `View.ItemText` and `EventHandler.RemoveSelfFromList`
    // detect they're inside the template and emit iteration-aware code.
    private var inItemTemplate: Boolean                          = false
    private var currentItemList: Option[ReactiveSignalList[?]]   = None
    private val statementStack: scala.collection.mutable.Stack[scala.collection.mutable.ArrayBuffer[String]] =
      scala.collection.mutable.Stack.empty

    /** Statements buffer the current `compile` recursion writes to.
     *  Defaults to the module-level outer buffer; `captureStatements`
     *  pushes a temporary one for sub-scopes (e.g. an item-template
     *  body that becomes a JS function literal). */
    def statements: scala.collection.mutable.ArrayBuffer[String] =
      if statementStack.isEmpty then _outerStatements
      else statementStack.top

    /** Run `body` with statements going to a fresh buffer; return the
     *  buffer when done.  Used to capture the body of a render-item
     *  function so we can wrap it as a JS `function (item, idx) { ... }`. */
    private def captureStatements[T](body: => T): (T, Seq[String]) =
      val buf = scala.collection.mutable.ArrayBuffer.empty[String]
      statementStack.push(buf)
      try (body, buf.toSeq)
      finally statementStack.pop()

    private def freshVar(): String =
      val v = s"n$counter"
      counter += 1
      v

    /** Validate + register a ReactiveSignal.  Name uniqueness is
     *  enforced (two signals with same jsName but different
     *  initial values throws — that's a user error worth catching
     *  early). */
    private def registerSignal(signal: ReactiveSignal[?]): Unit =
      val name = signal.id
      if !name.matches("[A-Za-z_][A-Za-z0-9_]*") then
        throw new IllegalArgumentException(
          s"ReactiveSignal id '$name' must match [A-Za-z_][A-Za-z0-9_]*."
        )
      val initialJs = jsLiteral(signal())
      reactiveSignals.get(name) match
        case Some(existing) if existing != initialJs =>
          throw new IllegalArgumentException(
            s"ReactiveSignal id '$name' registered twice with different " +
            s"initial values ($existing vs $initialJs).  Names must be unique."
          )
        case _ => reactiveSignals.update(name, initialJs)

    /** A2e — same uniqueness contract as `registerSignal` but for
     *  list cells: name validation + duplicate-initial check. */
    private def registerList(list: ReactiveSignalList[?]): Unit =
      val name = list.id
      if !name.matches("[A-Za-z_][A-Za-z0-9_]*") then
        throw new IllegalArgumentException(
          s"ReactiveSignalList id '$name' must match [A-Za-z_][A-Za-z0-9_]*."
        )
      val initialJs = jsArrayLiteral(list.initial)
      reactiveLists.get(name) match
        case Some(existing) if existing != initialJs =>
          throw new IllegalArgumentException(
            s"ReactiveSignalList id '$name' registered twice with different " +
            s"initial values ($existing vs $initialJs).  Names must be unique."
          )
        case _ => reactiveLists.update(name, initialJs)

    /** A6 — register a DomRef name + validate identifier shape.
     *  Same naming rule as ReactiveSignal: `[A-Za-z_][A-Za-z0-9_]*`. */
    private def registerRef(ref: WidgetRef): Unit =
      val name = ref.id
      if !name.matches("[A-Za-z_][A-Za-z0-9_]*") then
        throw new IllegalArgumentException(
          s"WidgetRef id '$name' must match [A-Za-z_][A-Za-z0-9_]*."
        )
      domRefs += name

    /** Compile a View node.  Returns the JS variable name that
     *  references the constructed DOM node, or `null` if the View
     *  emits zero nodes (an empty Fragment).  Caller decides whether
     *  to `appendChild` it. */
    @nowarn("cat=deprecation")
    def compile(view: View[?]): String | Null = view match
      case View.Element(tag, attrs, events, children) =>
        val v = freshVar()
        statements += s"const $v = document.createElement(${jsString(tag)});"
        attrs.foreach { (k, av) =>
          av match
            case AttrValue.RefBinding(ref) =>
              // A6 — bind the DOM ref AFTER createElement so the JS-side
              // variable holds the live node.  Element key (`k`) is
              // conventionally "ref" but we ignore it: the binding is
              // the RefBinding itself, not the attr name.
              registerRef(ref)
              statements += s"${ref.id} = $v;"
            case AttrValue.Bool(value) =>
              // Boolean IDL attributes (disabled, checked, required, …) must use
              // property assignment — setAttribute("disabled","false") leaves the
              // attribute present so the browser keeps the element disabled.
              // Hyphenated names (aria-*, data-*) can't be JS property identifiers.
              if k.contains('-') then
                statements += s"$v.setAttribute(${jsString(k)}, ${jsString(value.toString)});"
              else
                statements += s"$v.$k = $value;"
            case AttrValue.Reactive(signal) =>
              // Reactive attrs: set initial value as a property + subscribe so
              // future __setSignal calls keep the DOM property in sync.
              registerSignal(signal)
              val sigJs = jsString(signal.id)
              if k.contains('-') then
                statements += s"$v.setAttribute(${jsString(k)}, String(__ssc_signals[$sigJs].value));"
                statements += s"__ssc_signals[$sigJs].subs.add((nv) => { $v.setAttribute(${jsString(k)}, String(nv)); });"
              else
                statements += s"$v.$k = __ssc_signals[$sigJs].value;"
                statements += s"__ssc_signals[$sigJs].subs.add((nv) => { $v.$k = nv; });"
            case _ =>
              attrValueJs(av) match
                case Some(value) =>
                  statements += s"$v.setAttribute(${jsString(k)}, $value);"
                case None => () // Absent — skip
        }
        events.foreach { (eventName, handler) =>
          compileEventHandler(v, eventName, handler)
        }
        children.foreach { child =>
          val childVar = compile(child)
          if childVar != null then statements += s"$v.appendChild($childVar);"
        }
        v

      case View.TextNode(thunk) =>
        // Static — call once, embed as literal.
        val text = thunk()
        val v = freshVar()
        statements += s"const $v = document.createTextNode(${jsString(text)});"
        v

      case View.SignalText(signal, _) =>
        // Reactive — register the cell, create a text node bound
        // to its initial value, subscribe so future __setSignal
        // calls update the DOM.
        registerSignal(signal)
        val v = freshVar()
        val sigJs = jsString(signal.id)
        statements += s"const $v = document.createTextNode(__ssc_signals[$sigJs].value);"
        statements += s"__ssc_signals[$sigJs].subs.add((v) => { $v.textContent = v; });"
        v

      case View.Fragment(children) =>
        // Inline children into the parent — no DOM wrapper.  Return
        // null when the fragment is empty so the caller skips the
        // `appendChild`.
        if children.isEmpty then null
        else
          // Multi-child fragment: build a DocumentFragment so the
          // caller's single `appendChild` flushes all children.
          val v = freshVar()
          statements += s"const $v = document.createDocumentFragment();"
          children.foreach { child =>
            val childVar = compile(child)
            if childVar != null then statements += s"$v.appendChild($childVar);"
          }
          v

      case View.ComponentInstance(component, props) =>
        // Inline the component by calling its render(props) at emit
        // time and compiling the returned View.  This works as long
        // as the component's render is pure (no signal subscriptions
        // we need to wire up); A2b will switch to a structured IR.
        compile(component.render(props))

      case View.Show(cond, whenTrue, whenFalse) =>
        // Snapshot: pick the branch that cond() returns NOW.  Use
        // ShowSignal for reactive swap.
        val branch = if cond() then whenTrue() else whenFalse()
        compile(branch)

      case View.ShowSignal(cond, whenTrue, whenFalse) =>
        // Build a <span> wrapper, pre-compile BOTH branches up
        // front (so all nested signal subscribers register), and
        // subscribe to cond: on change, replaceChild swaps the
        // currently mounted branch.  The wrapper is the variable
        // returned to the parent.
        registerSignal(cond)
        val wrap     = freshVar()
        statements += s"const $wrap = document.createElement('span');"
        val tVar = compile(whenTrue)
        val fVar = compile(whenFalse)
        // Some branches may be empty Fragments — fall back to a
        // hidden text node so replaceChild always has something
        // to swap.  Use null-coalesce at JS layer via document fragment.
        val tNode = if tVar != null then tVar else placeholderNode()
        val fNode = if fVar != null then fVar else placeholderNode()
        val currentVar = s"__show_${wrap}_current"
        val condJs = jsString(cond.id)
        statements += s"let $currentVar = __ssc_signals[$condJs].value ? $tNode : $fNode;"
        statements += s"$wrap.appendChild($currentVar);"
        statements += s"__ssc_signals[$condJs].subs.add((v) => {"
        statements += s"  const next = v ? $tNode : $fNode;"
        statements += s"  if (next !== $currentVar) { $wrap.replaceChild(next, $currentVar); $currentVar = next; }"
        statements += s"});"
        wrap

      case View.For(items, render) =>
        // Snapshot iteration: realise items() once and inline each
        // rendered view.  Phase A2b: emit a keyed-list reactive
        // patch loop.
        val realised = items()
        if realised.isEmpty then null
        else
          val v = freshVar()
          statements += s"const $v = document.createDocumentFragment();"
          realised.foreach { item =>
            val childVar = compile(render(item))
            if childVar != null then statements += s"$v.appendChild($childVar);"
          }
          v

      case View.ForSignal(list, tag, attrs, itemTemplate) =>
        // A2e + A2e.2 — reactive list.  Build a wrapper element,
        // populate from the initial list, subscribe so list changes
        // wipe-and-rebuild children.  Two flavours:
        //
        //  - `itemTemplate = None` (A2e): each item is rendered as
        //    `<tag attrs>String(item)</tag>` — simple per-item element.
        //  - `itemTemplate = Some(template)` (A2e.2): walk the template
        //    inside a captured sub-scope so `View.ItemText` and
        //    `EventHandler.RemoveSelfFromList` see `inItemTemplate=true`
        //    and emit code that reads the iteration variable + index.
        registerList(list)
        val wrap     = freshVar()
        val nameJs   = jsString(list.id)
        val renderFn = s"__render_item_${list.id}"
        statements += s"const $wrap = document.createElement('span');"

        itemTemplate match
          case None =>
            // Simple form — emit the same shape A2e shipped.
            val tagJs = jsString(tag)
            val attrSetters = attrs.toSeq.flatMap { (k, av) =>
              attrValueJs(av).map(value => s"el.setAttribute(${jsString(k)}, $value);")
            }
            val attrSettersJs = if attrSetters.isEmpty then "" else attrSetters.mkString(" ")
            statements += s"function $renderFn(__item, __idx) {"
            statements += s"  const el = document.createElement($tagJs);"
            if attrSettersJs.nonEmpty then statements += s"  $attrSettersJs"
            statements += s"  el.textContent = String(__item);"
            statements += s"  return el;"
            statements += s"}"

          case Some(template) =>
            // Rich form — compile the template inside a captured
            // sub-scope so the buffered statements become the render-
            // item function body.  `inItemTemplate`/`currentItemList`
            // route ItemText + RemoveSelfFromList to the iteration vars.
            val prevFlag = inItemTemplate
            val prevList = currentItemList
            inItemTemplate  = true
            currentItemList = Some(list)
            val (rootVar, body) =
              try captureStatements(compile(template))
              finally
                inItemTemplate  = prevFlag
                currentItemList = prevList
            statements += s"function $renderFn(__item, __idx) {"
            body.foreach(stmt => statements += s"  $stmt")
            if rootVar == null then
              // Template compiled to nothing — fall back to a placeholder
              // so iteration still produces a Node.
              statements += s"  return document.createTextNode('');"
            else
              statements += s"  return $rootVar;"
            statements += s"}"

        statements += s"{ let __idx = 0; for (const __item of __ssc_lists[$nameJs].value) { $wrap.appendChild($renderFn(__item, __idx)); __idx++; } }"
        statements += s"__ssc_lists[$nameJs].subs.add((list) => {"
        statements += s"  while ($wrap.firstChild) $wrap.removeChild($wrap.firstChild);"
        statements += s"  let __idx = 0; for (const __item of list) { $wrap.appendChild($renderFn(__item, __idx)); __idx++; }"
        statements += s"});"
        wrap

      case View.ItemText =>
        // A2e.2 — placeholder for `String(__item)`.  Outside an item
        // template, emit an inert empty text node (graceful no-op).
        val v = freshVar()
        if inItemTemplate then
          statements += s"const $v = document.createTextNode(String(__item));"
        else
          statements += s"const $v = document.createTextNode('');"
        v

      case View.Portal(target, children) =>
        // A6 — render children into a foreign DOM location.  Compile each
        // child as usual, then `document.querySelector(target).appendChild`
        // it instead of returning a node to the caller.  Returns null so
        // the parent does NOT append anything (portal is a side-effect).
        val targetVar = freshVar()
        statements += s"const $targetVar = document.querySelector(${jsString(target)});"
        statements += s"if (!$targetVar) throw new Error('Portal target not found: ${target.replace("'", "\\'")}');"
        children.foreach { child =>
          val childVar = compile(child)
          if childVar != null then statements += s"$targetVar.appendChild($childVar);"
        }
        null

      case View.FetchTable(tableId, fetchUrl, deleteUrl, tick) =>
        registerSignal(tick)
        if !reactiveSignals.contains(tableId) then reactiveSignals.update(tableId, "[]")
        val tickJs     = jsString(tick.id)
        val rowsJs     = jsString(tableId)
        val urlJs      = jsString(fetchUrl)
        val delUrlJs   = jsString(deleteUrl)
        val thStyle    = jsString("text-align:left;padding:6px 12px;border-bottom:2px solid #e5e7eb;font-weight:600;color:#111827")
        val tdStyle    = jsString("padding:6px 12px;border-bottom:1px solid #e5e7eb;color:#374151;vertical-align:middle")
        val btnStyle   = jsString("background:#ef4444;color:#fff;border:none;padding:3px 10px;border-radius:4px;cursor:pointer;font-size:13px")
        val tableStyle = jsString("border-collapse:collapse;width:100%;font-family:sans-serif;font-size:14px")
        val theadStyle = jsString("background:#f9fafb")
        val tableVar = freshVar(); val theadVar = freshVar(); val trHVar = freshVar()
        val th1Var   = freshVar(); val th2Var   = freshVar(); val tbodyVar = freshVar()
        val rebuildFn = s"__rebuild_$tableId"
        statements += s"const $tableVar = document.createElement('table'); $tableVar.setAttribute('style', $tableStyle);"
        statements += s"const $theadVar = document.createElement('thead'); $theadVar.setAttribute('style', $theadStyle);"
        statements += s"const $trHVar = document.createElement('tr');"
        statements += s"const $th1Var = document.createElement('th'); $th1Var.setAttribute('style', $thStyle); $th1Var.textContent = 'Task'; $trHVar.appendChild($th1Var);"
        statements += s"const $th2Var = document.createElement('th'); $th2Var.setAttribute('style', $thStyle); $th2Var.textContent = ''; $trHVar.appendChild($th2Var);"
        statements += s"$theadVar.appendChild($trHVar); $tableVar.appendChild($theadVar);"
        statements += s"const $tbodyVar = document.createElement('tbody'); $tableVar.appendChild($tbodyVar);"
        statements += s"function $rebuildFn(rows) {"
        statements += s"  while ($tbodyVar.firstChild) $tbodyVar.removeChild($tbodyVar.firstChild);"
        statements += s"  for (const row of rows) {"
        statements += s"    const tr = document.createElement('tr');"
        statements += s"    const td1 = document.createElement('td'); td1.setAttribute('style', $tdStyle); td1.textContent = String(row.text); tr.appendChild(td1);"
        statements += s"    const td2 = document.createElement('td'); td2.setAttribute('style', $tdStyle);"
        statements += s"    const btn = document.createElement('button'); btn.setAttribute('style', $btnStyle); btn.textContent = 'Delete';"
        statements += s"    btn.addEventListener('click', () => fetch($delUrlJs, {method: 'POST', body: String(row.id)}).then(r => r.text()).then(_ => __setSignal($tickJs, __ssc_signals[$tickJs].value + 1)));"
        statements += s"    td2.appendChild(btn); tr.appendChild(td2); $tbodyVar.appendChild(tr);"
        statements += s"  }"
        statements += s"}"
        statements += s"__ssc_signals[$rowsJs].subs.add($rebuildFn);"
        statements += s"__ssc_signals[$tickJs].subs.add((t) => { if (t > 0) fetch($urlJs).then(r => r.json()).then(data => __setSignal($rowsJs, data)); });"
        statements += s"fetch($urlJs).then(r => r.json()).then(data => __setSignal($rowsJs, data));"
        tableVar

      case v: View[?] =>
        val commentVar = freshVar()
        statements += s"const $commentVar = document.createComment('[unsupported on web in P1: ${v.getClass.getSimpleName}]');"
        commentVar

    /** Empty-branch placeholder for ShowSignal — an empty text
     *  node so `replaceChild` always has a real Node to swap.
     *  Phase A2d: a hidden no-op. */
    private def placeholderNode(): String =
      val v = freshVar()
      statements += s"const $v = document.createTextNode('');"
      v

    private def attrValueJs(av: AttrValue): Option[String] = av match
      case AttrValue.Str(value)        => Some(jsString(value))
      case AttrValue.Bool(_)           => None  // handled as property assignment before attrValueJs is called
      case AttrValue.Num(value)        => Some(formatNumber(value))
      case AttrValue.Dynamic(read)     => Some(jsString(String.valueOf(read()))) // snapshot
      case AttrValue.Reactive(_)       => None  // handled as reactive subscription before attrValueJs is called
      case AttrValue.Absent            => None
      case AttrValue.RefBinding(_)     => None  // ref binding is wired imperatively in the Element case; no setAttribute

    private def formatNumber(d: Double): String =
      if d == d.toLong.toDouble then d.toLong.toString else d.toString

    /** Compile a single event handler into an `addEventListener`
     *  call on `targetVar`.  Simple / WithEvent are JVM closures
     *  that we can't translate to JS without a richer IR — they
     *  emit a marker comment for now.  SetSignalLiteral and
     *  IncrementSignal are A2c additions that lower cleanly. */
    private def compileEventHandler(targetVar: String, eventName: String, handler: EventHandler): Unit =
      handler match
        case EventHandler.Simple(_) | EventHandler.WithEvent(_) =>
          statements +=
            s"// $targetVar: '$eventName' handler is a JVM closure — A2c can't translate;" +
            " richer IR coming later."
        case EventHandler.InputChange(signal) =>
          registerSignal(signal)
          val nameJs = jsString(signal.id)
          statements += s"$targetVar.addEventListener('input', (e) => __setSignal($nameJs, e.target.value));"
        case EventHandler.SetSignalLiteral(signal, value) =>
          registerSignal(signal)
          val nameJs  = jsString(signal.id)
          val valueJs = jsLiteral(value)
          statements += s"$targetVar.addEventListener(${jsString(eventName)}, () => " +
                        s"__setSignal($nameJs, $valueJs));"
        case EventHandler.IncrementSignal(signal, by) =>
          registerSignal(signal)
          val nameJs = jsString(signal.id)
          statements += s"$targetVar.addEventListener(${jsString(eventName)}, () => " +
                        s"__setSignal($nameJs, __ssc_signals[$nameJs].value + $by));"
        case EventHandler.ToggleSignal(signal) =>
          registerSignal(signal)
          val nameJs = jsString(signal.id)
          statements += s"$targetVar.addEventListener(${jsString(eventName)}, () => " +
                        s"__setSignal($nameJs, !__ssc_signals[$nameJs].value));"
        case EventHandler.PushSignalLiteral(list, value) =>
          registerList(list)
          val nameJs  = jsString(list.id)
          val valueJs = jsLiteral(value)
          statements += s"$targetVar.addEventListener(${jsString(eventName)}, () => " +
                        s"__setSignalList($nameJs, __ssc_lists[$nameJs].value.concat([$valueJs])));"
        case EventHandler.ClearSignalList(list) =>
          registerList(list)
          val nameJs = jsString(list.id)
          statements += s"$targetVar.addEventListener(${jsString(eventName)}, () => " +
                        s"__setSignalList($nameJs, []));"
        case EventHandler.FetchAction(method, url, body, tick, clearBody) =>
          registerSignal(body)
          registerSignal(tick)
          val bodyJs   = jsString(body.id)
          val tickJs   = jsString(tick.id)
          val urlJs    = jsString(url)
          val methodJs = jsString(method)
          val clearJs  = if clearBody then s" __setSignal($bodyJs, '');" else ""
          statements += s"$targetVar.addEventListener(${jsString(eventName)}, () => " +
            s"fetch($urlJs, {method: $methodJs, body: __ssc_signals[$bodyJs].value})" +
            s".then(r => r.text()).then(_ => { __setSignal($tickJs, __ssc_signals[$tickJs].value + 1);$clearJs }));"
        case EventHandler.RemoveSelfFromList(list) =>
          // A2e.2 — only meaningful inside an item template; outside,
          // emit an inert listener (graceful no-op).
          if inItemTemplate && currentItemList.exists(_.id == list.id) then
            registerList(list)
            val nameJs = jsString(list.id)
            // Capture __idx in the per-item closure so each instance
            // knows its own position; on click we filter that index out.
            statements += s"$targetVar.addEventListener(${jsString(eventName)}, ((__capturedIdx) => () => " +
                          s"__setSignalList($nameJs, __ssc_lists[$nameJs].value.filter((_, i) => i !== __capturedIdx)))(__idx));"
          else
            statements +=
              s"// $targetVar: '$eventName' is RemoveSelfFromList used outside an item template — no-op."

  /** A2e — JS array literal for a `ReactiveSignalList`'s initial
   *  value.  Each element goes through `jsLiteral` (same primitive
   *  type restriction as scalar signals). */
  private def jsArrayLiteral(items: Seq[Any]): String =
    items.map(jsLiteral).mkString("[", ", ", "]")

  /** JS literal for a signal value or SetSignalLiteral payload.
   *  Dispatches on runtime class because the trait surface is
   *  type-erased at the IR boundary. */
  private def jsLiteral(value: Any): String = value match
    case s: String     => jsString(s)
    case i: Int        => i.toString
    case l: Long       => l.toString
    case d: Double     => if d == d.toLong.toDouble then d.toLong.toString else d.toString
    case f: Float      => f.toDouble.toString
    case b: Boolean    => b.toString
    case null          => "null"
    case other         => throw new IllegalArgumentException(
      s"jsLiteral: unsupported value type ${other.getClass.getName} ($other).  " +
      "Supported: String / Int / Long / Double / Float / Boolean / null."
    )

  /** JS-encoded string literal — escapes the four characters
   *  (`\\`, `'`, newline, CR) that can break a single-quoted JS
   *  literal.  Other Unicode is passed through unchanged; the
   *  generated bundle is UTF-8 anyway. */
  private def jsString(s: String): String =
    val sb = new StringBuilder
    sb += '\''
    s.foreach {
      case '\\' => sb ++= "\\\\"
      case '\'' => sb ++= "\\'"
      case '\n' => sb ++= "\\n"
      case '\r' => sb ++= "\\r"
      case '<'  => sb ++= "\\u003c"  // belt-and-suspenders for inline scripts
      case c    => sb += c
    }
    sb += '\''
    sb.toString
